func NewServer(cfg *Config) *Server {
	gin.SetMode(gin.ReleaseMode)
	engine := gin.New()
	engine.Use(gin.Recovery())
	engine.Use(loggingMiddleware())

	engine.GET("/health", handleHealth)

	v1 := engine.Group("/v1")
	v1.Use(authMiddleware(cfg.EnableAuth))
