		v1.DELETE("/code-interpreter", handleCodeInterpreterDelete)
	}

	return &Server{
		config: cfg,
		engine: engine,
		server: &http.Server{
			Addr:        cfg.Addr(),
			Handler:     engine,
			ReadTimeout: 15 * time.Second,
			IdleTimeout: 90 * time.Second,
		},
	}
}

func (s *Server) Start() error {
	storeInstance := storepkg.Storage()
	if err := storeInstance.Ping(); err != nil {
		return fmt.Errorf("failed to ping store: %w", err)
	}

	informers := NewInformers()
	ctx, cancel := context.WithTimeout(context.Background(), 1*time.Minute)
	defer cancel()
	if err := informers.SyncWithTimeout(ctx); err != nil {
		klog.Warningf("failed to sync informers: %v", err)
	}

	go s.startGarbageCollector(context.Background())

	klog.Infof("Starting workload manager server on %s", s.config.Addr())

	go func() {
		if s.config.EnableTLS {
			if err := s.server.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey); err != nil && err != http.ErrServerClosed {
				klog.Fatalf("failed to start server: %v", err)
			}
		} else {
			if err := s.server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
				klog.Fatalf("failed to start server: %v", err)
			}
		}
	}()

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
	<-sigCh

	klog.Info("Shutting down workload manager server...")
	shutdownCtx, shutdownCancel := context.WithTimeout(context.Background(), 15*time.Second)
	defer shutdownCancel()

	if err := s.server.Shutdown(shutdownCtx); err != nil {
		klog.Errorf("failed to shutdown server: %v", err)
	}

	storeInstance.Close()
	return nil
}

func (s *Server) startGarbageCollector(ctx context.Context) {
	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			gcCtx, cancel := context.WithTimeout(context.Background(), 2*time.Minute)
			runGarbageCollector(gcCtx)
			cancel()
		}
	}
}

func loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path
		c.Next()
		klog.V(4).Infof("%s %s %d %v", c.Request.Method, path, c.Writer.Status(), time.Since(start))
	}
}

func authMiddleware(enabled bool) gin.HandlerFunc {
	if !enabled {
		return func(c *gin.Context) {
			c.Next()
		}
	}

	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "authorization header required"})
			c.Abort()
			return
		}

		parts := strings.SplitN(authHeader, " ", 2)
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid authorization header format"})
			c.Abort()
			return
		}

		token := parts[1]
		sa, err := validateServiceAccountToken(token)
		if err != nil {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
			c.Abort()
			return
		}

		c.Set("serviceAccount", sa)
		c.Set("userToken", token)
		c.Next()
	}
}

func handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

