package workloadmanager

import (
	"context"
	"fmt"

	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/runtime/schema"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

const (
	SandboxPodNameAnnotation = "agents.x-k8s.io/sandbox-pod-name"
	SandboxNameLabel         = "runtime.agentcube.io/sandbox-name"
	SandboxManagedByLabel    = "managed-by"
	SandboxManagedByValue    = "agentcube-workload-manager"
	IdentitySecretName       = "picod-router-identity"
	PublicKeyDataKey        = "public.pem"
)

func buildSandboxObject(req *types.CreateSandboxRequest, podIP, podName string) (runtime.Object, error) {
	gvk := schema.GroupVersionKind{
		Group:   "agents.x-k8s.io",
		Version: "v1alpha1",
		Kind:    "Sandbox",
	}

	obj := &Sandbox{
		TypeMeta: metav1.TypeMeta{
			APIVersion: gvk.GroupVersion().String(),
			Kind:       gvk.Kind,
		},
		ObjectMeta: metav1.ObjectMeta{
			Name:      req.Name,
			Namespace: req.Namespace,
			Labels: map[string]string{
				SandboxManagedByLabel: SandboxManagedByValue,
			},
			Annotations: map[string]string{
				SandboxPodNameAnnotation: podName,
			},
		},
		Spec: SandboxSpec{
			RuntimeClassName: "kuasar-vmm",
		},
	}

	return obj, nil
}

func buildSandboxClaimObject(req *types.CreateSandboxRequest, podIP, podName string) (runtime.Object, error) {
	gvk := schema.GroupVersionKind{
		Group:   "extensions.agents.x-k8s.io",
		Version: "v1alpha1",
		Kind:    "SandboxClaim",
	}

	obj := &SandboxClaim{
		TypeMeta: metav1.TypeMeta{
			APIVersion: gvk.GroupVersion().String(),
			Kind:       gvk.Kind,
		},
		ObjectMeta: metav1.ObjectMeta{
			Name:      req.Name + "-claim",
			Namespace: req.Namespace,
			Labels: map[string]string{
				SandboxManagedByLabel: SandboxManagedByValue,
			},
		},
		Spec: SandboxClaimSpec{
			RuntimeClassName: "kuasar-vmm",
			Template: corev1.PodTemplateSpec{
				ObjectMeta: metav1.ObjectMeta{
					Labels: map[string]string{
						SandboxNameLabel: req.Name,
					},
				},
			},
		},
	}

	return obj, nil
}

func buildEntryPoints(podIP string, ports []int32) []types.SandboxEntryPoint {
	var entryPoints []types.SandboxEntryPoint
	for i, port := range ports {
		entryPoints = append(entryPoints, types.SandboxEntryPoint{
			Name:       fmt.Sprintf("port-%d", i),
			Path:       "/",
			Protocol:   "HTTP",
			TargetPort: port,
		})
	}
	return entryPoints
}

func resolvePodIP(ctx context.Context, namespace, sandboxName, podNameAnnotation string) (string, error) {
	config, err := GetKubernetesConfig()
	if err != nil {
		return "", err
	}

	clientset, err := GetKubernetesClientset(config)
	if err != nil {
		return "", err
	}

	if podNameAnnotation != "" {
		pod, err := clientset.CoreV1().Pods(namespace).Get(ctx, podNameAnnotation, metav1.GetOptions{})
		if err == nil && pod.Status.PodIP != "" {
			return pod.Status.PodIP, nil
		}
	}

	labelSelector := fmt.Sprintf("%s=%s", SandboxNameLabel, sandboxName)
	pods, err := clientset.CoreV1().Pods(namespace).List(ctx, metav1.ListOptions{
		LabelSelector: labelSelector,
	})
	if err != nil {
		return "", err
	}

	for _, pod := range pods.Items {
		if pod.Status.PodIP != "" {
			for _, ownerRef := range pod.OwnerReferences {
				if ownerRef.Kind == "Sandbox" {
					return pod.Status.PodIP, nil
				}
			}
		}
	}

	return "", fmt.Errorf("pod IP not found for sandbox %s", sandboxName)
}

type Sandbox struct {
	metav1.TypeMeta   `json:",inline"`
	metav1.ObjectMeta `json:"metadata,omitempty"`
	Spec              SandboxSpec `json:"spec,omitempty"`
}

type SandboxSpec struct {
	RuntimeClassName string `json:"runtimeClassName,omitempty"`
}

type SandboxClaim struct {
	metav1.TypeMeta   `json:",inline"`
	metav1.ObjectMeta `json:"metadata,omitempty"`
	Spec              SandboxClaimSpec `json:"spec,omitempty"`
}

type SandboxClaimSpec struct {
	RuntimeClassName string              `json:"runtimeClassName,omitempty"`
	Template         corev1.PodTemplateSpec `json:"template,omitempty"`
}

