package workloadmanager

import (
	"context"
	"fmt"
	"sync"
	"time"

	authenticationv1 "k8s.io/api/authentication/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"
)

type TokenCache struct {
	mu      sync.RWMutex
	tokens  map[string]*cachedToken
	maxSize int
	ttl     time.Duration
}

type cachedToken struct {
	serviceAccount string
	expiry         time.Time
}

func NewTokenCache(maxSize int, ttl time.Duration) *TokenCache {
	return &TokenCache{
		tokens:  make(map[string]*cachedToken),
		maxSize: maxSize,
		ttl:     ttl,
	}
}

func (tc *TokenCache) Get(token string) (string, bool) {
	tc.mu.RLock()
	defer tc.mu.RUnlock()

	cached, ok := tc.tokens[token]
	if !ok {
		return "", false
	}

	if time.Now().After(cached.expiry) {
		return "", false
	}

	return cached.serviceAccount, true
}

func (tc *TokenCache) Set(token, serviceAccount string) {
	tc.mu.Lock()
	defer tc.mu.Unlock()

	if len(tc.tokens) >= tc.maxSize {
		tc.evictOldest()
	}

	tc.tokens[token] = &cachedToken{
		serviceAccount: serviceAccount,
		expiry:         time.Now().Add(tc.ttl),
	}
}

func (tc *TokenCache) evictOldest() {
	var oldestKey string
	var oldestTime time.Time
	first := true

	for key, cached := range tc.tokens {
		if first || cached.expiry.Before(oldestTime) {
			oldestKey = key
			oldestTime = cached.expiry
			first = false
		}
	}

	if oldestKey != "" {
		delete(tc.tokens, oldestKey)
	}
}

var globalTokenCache = NewTokenCache(1000, 5*time.Minute)

func validateServiceAccountToken(token string) (string, error) {
	if sa, ok := globalTokenCache.Get(token); ok {
		return sa, nil
	}

	config, err := GetKubernetesConfig()
	if err != nil {
		return "", fmt.Errorf("failed to get kubernetes config: %w", err)
	}

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return "", fmt.Errorf("failed to create kubernetes client: %w", err)
	}

	review := &authenticationv1.TokenReview{
		Spec: authenticationv1.TokenReviewSpec{
			Token: token,
		},
	}

	result, err := clientset.AuthenticationV1().TokenReviews().Create(context.Background(), review, metav1.CreateOptions{})
	if err != nil {
		return "", fmt.Errorf("failed to create token review: %w", err)
	}

	if !result.Status.Authenticated {
		return "", fmt.Errorf("token not authenticated")
	}

	username := result.Status.User.Username
	globalTokenCache.Set(token, username)

	return username, nil
}

