	config, err := GetKubernetesConfig()
	if err != nil {
		klog.Warningf("failed to get config for informers: %v", err)
		return &Informers{}
	}

	config.QPS = 50
	config.Burst = 100

	clientset, err := GetKubernetesClientset(config)
	if err != nil {
		klog.Warningf("failed to create clientset for informers: %v", err)
		return &Informers{}
	}

	factory := informers.NewSharedInformerFactory(clientset, 1*time.Minute)
	dynamicFactory := dynamicinformer.NewFilteredDynamicSharedInformerFactory(dynamic.NewForConfigOrDie(config), 1*time.Minute, metav1.NamespaceAll, nil)

	return &Informers{
		factory:        factory,
		dynamicFactory: dynamicFactory,
	}
}

func (i *Informers) SyncWithTimeout(ctx context.Context) error {
	if i.factory == nil {
		return nil
	}

	i.factory.Start(ctx.Done())
	i.factory.WaitForCacheSync(ctx.Done())

	if i.dynamicFactory != nil {
		i.dynamicFactory.Start(ctx.Done())
		i.dynamicFactory.WaitForCacheSync(ctx.Done())
	}

	return nil
}

func (i *Informers) Start(stopCh <-chan struct{}) {
	if i.factory != nil {
		i.factory.Start(stopCh)
	}
	if i.dynamicFactory != nil {
		i.dynamicFactory.Start(stopCh)
	}
}

func (i *Informers) WaitForCacheSync(stopCh <-chan struct{}) bool {
	if i.factory != nil {
		if !i.factory.WaitForCacheSync(stopCh) {
			return false
		}
	}
	if i.dynamicFactory != nil {
		if !i.dynamicFactory.WaitForCacheSync(stopCh) {
			return false
		}
	}
	return true
}

func GetKubernetesConfig() (*rest.Config, error) {
	return rest.InClusterConfig()
}

func GetKubernetesClientset(config *rest.Config) (*kubernetes.Clientset, error) {
	return kubernetes.NewForConfig(config)
}

