package workloadmanager

import (
	"context"
	"time"

	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/store"
)

const (
	inactiveCutoffDuration = 15 * time.Minute
	gcBatchSize            = 16
)

func runGarbageCollector(ctx context.Context) {
	storeInstance := Storage()
	now := time.Now()
	inactiveBefore := now.Add(-inactiveCutoffDuration).Unix()
	expiredBefore := now.Unix()

	inactiveSandboxes, err := storeInstance.ListInactiveSandboxes(inactiveBefore, gcBatchSize)
	if err != nil {
		klog.Errorf("failed to list inactive sandboxes: %v", err)
		return
	}

	expiredSandboxes, err := storeInstance.ListExpiredSandboxes(expiredBefore, gcBatchSize)
	if err != nil {
		klog.Errorf("failed to list expired sandboxes: %v", err)
		return
	}

	sandboxMap := make(map[string]*store.SandboxInfo)
	for _, s := range inactiveSandboxes {
		sandboxMap[s.ID] = s
	}
	for _, s := range expiredSandboxes {
		sandboxMap[s.ID] = s
	}

	for _, s := range sandboxMap {
		if err := deleteSandbox(s.ID, s.Namespace); err != nil {
			klog.Errorf("failed to delete sandbox %s: %v", s.ID, err)
			continue
		}
		klog.Infof("garbage collected sandbox %s", s.ID)
	}
}

