package workloadmanager

import (
	"context"
	"fmt"
	"time"

	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/api"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

func Storage() store.Store {
	return storepkg.Storage()
}

func createSandbox(req *types.CreateSandboxRequest) (string, *types.SandboxInfo, error) {
	storeInstance := Storage()
	sessionID := generateSessionID()

	sandboxInfo := &types.SandboxInfo{
		ID:        sessionID,
		Kind:      req.Kind,
		Namespace: req.Namespace,
		Name:      req.Name,
		ExpiresAt: time.Now().Add(8 * time.Hour).Unix(),
	}

	if err := storeInstance.StoreSandbox(sessionID, sandboxInfo); err != nil {
		return "", nil, fmt.Errorf("failed to store sandbox: %w", err)
	}

	return sessionID, sandboxInfo, nil
}

func deleteSandbox(sessionID, namespace string) error {
	storeInstance := Storage()

	info, err := storeInstance.GetSandboxBySessionID(sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			return nil
		}
		return err
	}

	if err := storeInstance.DeleteSandboxBySessionID(sessionID); err != nil {
		return err
	}

	klog.Infof("deleted sandbox %s from store", sessionID)
	return nil
}

func generateSessionID() string {
	return fmt.Sprintf("sess-%d", time.Now().UnixNano())
}

