package agentd

import (
	"context"
	"time"

	"k8s.io/apimachinery/pkg/runtime"
	ctrl "sigs.k8s.io/controller-runtime"
	"sigs.k8s.io/controller-runtime/pkg/client"

	agentsv1alpha1 "sigs.k8s.io/agent-sandbox/pkg/apis/agents/v1alpha1"

	"github.com/volcano-sh/agentcube/pkg/workloadmanager"
)

const (
	SessionExpirationTimeout = 15 * time.Minute
)

type Reconciler struct {
	client.Client
	Scheme *runtime.Scheme
}

func (r *Reconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
	sandbox := &agentsv1alpha1.Sandbox{}
	if err := r.Get(ctx, req.NamespacedName, sandbox); err != nil {
		if client.IgnoreNotFound(err) != nil {
			return ctrl.Result{}, err
		}
		return ctrl.Result{}, nil
	}

	lastActivityStr, ok := sandbox.Annotations[workloadmanager.LastActivityAnnotationKey]
	if !ok || lastActivityStr == "" {
		return ctrl.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		return ctrl.Result{RequeueAfter: 30 * time.Second}, nil
	}

	expirationTime := lastActivity.Add(SessionExpirationTimeout)
	if time.Now().After(expirationTime) {
		if err := r.Delete(ctx, sandbox); err != nil {
			if client.IgnoreNotFound(err) != nil {
				return ctrl.Result{}, err
			}
			return ctrl.Result{}, nil
		}
		return ctrl.Result{}, nil
	}

	return ctrl.Result{RequeueAfter: time.Until(expirationTime)}, nil
}

func (r *Reconciler) SetupWithManager(mgr ctrl.Manager) error {
	return ctrl.NewControllerManagedBy(mgr).
		For(&agentsv1alpha1.Sandbox{}).
		Complete(r)
}

package main

import (
	"flag"

	"k8s.io/klog/v2"
	"k8s.io/apimachinery/pkg/runtime"
	utilruntime "k8s.io/apimachinery/pkg/util/runtime"
	ctrl "sigs.k8s.io/controller-runtime"

	agentsv1alpha1 "sigs.k8s.io/agent-sandbox/pkg/apis/agents/v1alpha1"

	"github.com/volcano-sh/agentcube/pkg/agentd"
)

func main() {
	klog.InitFlags(nil)
	flag.Parse()

	scheme := runtime.NewScheme()
	utilruntime.Must(agentsv1alpha1.AddToScheme(scheme))

	mgr, err := ctrl.NewManager(ctrl.GetConfigOrDie(), ctrl.Options{
		Scheme:                 scheme,
		MetricsBindAddress:     "0",
		HealthProbeBindAddress: "0",
	})
	if err != nil {
		klog.Fatalf("failed to create manager: %v", err)
	}

	if err := (&agentd.Reconciler{
		Client: mgr.GetClient(),
		Scheme: mgr.GetScheme(),
	}).SetupWithManager(mgr); err != nil {
		klog.Fatalf("failed to set up reconciler: %v", err)
	}

	klog.Info("Starting agentd controller...")
	if err := mgr.Start(ctrl.SetupSignalHandler()); err != nil {
		klog.Fatalf("failed to start manager: %v", err)
	}
}

package picod

import (
	"fmt"
	"os"
)

type Config struct {
	Port      int
	Workspace string
}

func NewConfig() *Config {
	return &Config{
		Port:      8080,
		Workspace: os.Getenv("PICOD_WORKSPACE"),
	}
}

func (c *Config) Validate() error {
	if c.Port <= 0 || c.Port > 65535 {
		return fmt.Errorf("invalid port: %d", c.Port)
	}
	if c.Workspace == "" {
		c.Workspace = "."
	}
	return nil
}

package picod

import (
	"context"
	"crypto/rsa"
	"encoding/base64"
	"encoding/pem"
	"fmt"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
	"k8s.io/klog/v2"
)

type Server struct {
	config         *Config
	engine         *gin.Engine
	httpServer     *http.Server
	authManager    *AuthManager
	workspaceDir   string
	startTime      time.Time
}

func NewServer(cfg *Config) (*Server, error) {
	if err := cfg.Validate(); err != nil {
		return nil, err
	}

	gin.SetMode(gin.ReleaseMode)
	engine := gin.New()
	engine.Use(gin.Logger())
	engine.Use(gin.Recovery())

	authManager := NewAuthManager()
	if err := authManager.LoadPublicKeyFromEnv(); err != nil {
		return nil, fmt.Errorf("failed to load public key: %w", err)
	}

	workspaceDir, err := resolveWorkspace(cfg.Workspace)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve workspace: %w", err)
	}

	server := &Server{
		config:       cfg,
		engine:       engine,
		authManager:  authManager,
		workspaceDir: workspaceDir,
		startTime:    time.Now(),
	}

	server.setupRoutes()

	return server, nil
}

func (s *Server) setupRoutes() {
	s.engine.GET("/health", s.handleHealth)

	api := s.engine.Group("/api")
	api.Use(s.authManager.AuthMiddleware())
	{
		api.POST("/execute", s.handleExecute)
		api.POST("/files", s.handleUploadFile)
		api.GET("/files", s.handleListFiles)
		api.GET("/files/*path", s.handleDownloadFile)
	}
}

func (s *Server) Run() error {
	s.httpServer = &http.Server{
		Addr:              fmt.Sprintf(":%d", s.config.Port),
		Handler:           s.engine,
		ReadHeaderTimeout: 10 * time.Second,
	}
	klog.Infof("Starting PicoD server on port %d", s.config.Port)
	return s.httpServer.ListenAndServe()
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":   "ok",
		"service":  "PicoD",
		"version":  "0.0.1",
		"uptime":   time.Since(s.startTime).String(),
	})
}

func resolveWorkspace(workspace string) (string, error) {
	if workspace == "" {
		workspace = "."
	}
	absPath, err := os.Abs(workspace)
	if err != nil {
		return "", err
	}
	info, err := os.Stat(absPath)
	if err != nil {
		if os.IsNotExist(err) {
			return "", fmt.Errorf("workspace does not exist: %s", absPath)
		}
		return "", err
	}
	if !info.IsDir() {
		return "", fmt.Errorf("workspace is not a directory: %s", absPath)
	}
	return absPath, nil
}

type AuthManager struct {
	publicKey *rsa.PublicKey
	mu        sync.RWMutex
}

func NewAuthManager() *AuthManager {
	return &AuthManager{}
}

func (a *AuthManager) LoadPublicKeyFromEnv() error {
	keyData := os.Getenv("PICOD_AUTH_PUBLIC_KEY")
	if keyData == "" {
		return fmt.Errorf("PICOD_AUTH_PUBLIC_KEY environment variable is required")
	}

	pemData, err := base64.StdEncoding.DecodeString(keyData)
	if err != nil {
		pemData = []byte(keyData)
	}

	block, _ := pem.Decode(pemData)
	if block == nil {
		return fmt.Errorf("failed to decode PEM block")
	}

	pub, err := jwt.ParseRSAPublicKeyFromPEM(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	a.mu.Lock()
	defer a.mu.Unlock()
	a.publicKey = pub
	return nil
}

func (a *AuthManager) AuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "authorization header required"})
			return
		}

		parts := strings.SplitN(authHeader, " ", 2)
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid authorization header format"})
			return
		}

		tokenString := parts[1]

		a.mu.RLock()
		publicKey := a.publicKey
		a.mu.RUnlock()

		if publicKey == nil {
			c.AbortWithStatusJSON(http.StatusInternalServerError, gin.H{"error": "public key not initialized"})
			return
		}

		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
			}
			return publicKey, nil
		}, jwt.WithExpirationRequired(), jwt.WithIssuedAt(), jwt.WithLeeway(time.Minute))

		if err != nil || !token.Valid {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
			return
		}

		c.Next()
	}
}

